import React, { useState, useEffect, useCallback, useRef } from "react";
import { Search, RefreshCw, AlertCircle, TrendingUp } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Badge } from "@/components/ui/badge";
import { AnimatePresence, motion } from "framer-motion";
import { cn } from "@/lib/utils";
import { PolymarketEvent, Category } from "./types";
import { fetchEvents, CATEGORIES } from "./lib/api";
import MarketCard from "./components/MarketCard";

const POLL_INTERVAL = 60_000; // 60s

function App() {
  const [events, setEvents] = useState<PolymarketEvent[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useState("");
  const [activeCategory, setActiveCategory] = useState<Category>(CATEGORIES[0]);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [refreshing, setRefreshing] = useState(false);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const loadEvents = useCallback(
    async (showLoading = true) => {
      try {
        if (showLoading) setLoading(true);
        else setRefreshing(true);
        setError(null);
        const data = await fetchEvents(activeCategory.tagId, 50);
        setEvents(data);
        setLastUpdated(new Date());
      } catch (err: any) {
        setError(err.message || "Failed to fetch markets");
      } finally {
        setLoading(false);
        setRefreshing(false);
      }
    },
    [activeCategory]
  );

  useEffect(() => {
    loadEvents(true);

    if (intervalRef.current) clearInterval(intervalRef.current);
    intervalRef.current = setInterval(() => loadEvents(false), POLL_INTERVAL);

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [loadEvents]);

  const filteredEvents = events.filter((e) => {
    if (!search.trim()) return true;
    const q = search.toLowerCase();
    return (
      e.title?.toLowerCase().includes(q) ||
      e.description?.toLowerCase().includes(q) ||
      e.markets?.some((m) => m.question?.toLowerCase().includes(q))
    );
  });

  const totalVolume = events.reduce((sum, e) => sum + (e.volume24hr || 0), 0);

  return (
    <div className="w-full h-full flex flex-col overflow-hidden">
      {/* Stats bar */}
      <div className="px-4 pt-3 pb-2 flex items-center justify-between text-[11px] text-zinc-500 border-b border-zinc-800/50">
        <div className="flex items-center gap-3">
          <span className="flex items-center gap-1">
            <TrendingUp className="w-3 h-3 text-emerald-400" />
            <span className="text-zinc-300">{filteredEvents.length}</span>{" "}
            markets
          </span>
          {totalVolume > 0 && (
            <span>
              24h Vol:{" "}
              <span className="text-zinc-300">
                ${(totalVolume / 1_000_000).toFixed(1)}M
              </span>
            </span>
          )}
        </div>
        <div className="flex items-center gap-2">
          {lastUpdated && (
            <span>
              Updated{" "}
              {lastUpdated.toLocaleTimeString([], {
                hour: "2-digit",
                minute: "2-digit",
              })}
            </span>
          )}
          <Button
            variant="ghost"
            size="icon"
            className="h-5 w-5"
            onClick={() => loadEvents(false)}
            disabled={refreshing}
          >
            <RefreshCw
              className={cn("w-3 h-3", refreshing && "animate-spin")}
            />
          </Button>
        </div>
      </div>

      {/* Search */}
      <div className="px-4 pt-3 pb-2">
        <div className="relative">
          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-zinc-500" />
          <Input
            placeholder="Search markets..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-8 h-8 text-xs bg-zinc-900 border-zinc-800 text-zinc-100 placeholder:text-zinc-600 focus-visible:ring-zinc-700"
          />
        </div>
      </div>

      {/* Categories */}
      <div className="px-4 pb-2">
        <div className="flex gap-1 overflow-x-auto scrollbar-hide pb-1">
          {CATEGORIES.map((cat) => (
            <button
              key={cat.id}
              onClick={() => setActiveCategory(cat)}
              className={cn(
                "px-2.5 py-1 text-[11px] whitespace-nowrap transition-all shrink-0 border",
                activeCategory.id === cat.id
                  ? "bg-zinc-100 text-zinc-900 border-zinc-100 font-semibold"
                  : "bg-zinc-900 text-zinc-400 border-zinc-800 hover:border-zinc-600 hover:text-zinc-300"
              )}
            >
              {cat.label}
            </button>
          ))}
        </div>
      </div>

      {/* Error */}
      {error && (
        <div className="px-4 pb-2">
          <Alert variant="destructive" className="py-2">
            <AlertCircle className="w-3 h-3" />
            <AlertDescription className="text-xs">{error}</AlertDescription>
          </Alert>
        </div>
      )}

      {/* Content */}
      <ScrollArea className="flex-1 px-4">
        {loading ? (
          <div className="space-y-3 pb-4">
            {Array.from({ length: 8 }).map((_, i) => (
              <div key={i} className="bg-zinc-900 border border-zinc-800 p-3">
                <div className="flex gap-3">
                  <Skeleton className="w-10 h-10 bg-zinc-800" />
                  <div className="flex-1 space-y-2">
                    <Skeleton className="h-4 w-3/4 bg-zinc-800" />
                    <Skeleton className="h-3 w-1/2 bg-zinc-800" />
                  </div>
                  <Skeleton className="w-12 h-8 bg-zinc-800" />
                </div>
                <Skeleton className="h-5 w-full mt-2 bg-zinc-800" />
              </div>
            ))}
          </div>
