import { PolymarketEvent, Category } from "../types";

const GAMMA_BASE = "https://gamma-api.polymarket.com";

export const CATEGORIES: Category[] = [
  { id: "trending", label: "🔥 Trending", tagId: null },
  { id: "politics", label: "🏛️ Politics", tagId: 2 },
  { id: "finance", label: "💰 Finance", tagId: 120 },
  { id: "crypto", label: "₿ Crypto", tagId: 21 },
  { id: "sports", label: "⚽ Sports", tagId: 100639 },
  { id: "tech", label: "💻 Tech", tagId: 1401 },
  { id: "culture", label: "🎬 Culture", tagId: 596 },
  { id: "geopolitics", label: "🌍 Geopolitics", tagId: 100265 },
];

export async function fetchEvents(
  tagId: number | null,
  limit: number = 50,
  offset: number = 0
): Promise<PolymarketEvent[]> {
  let url = `${GAMMA_BASE}/events?active=true&closed=false&limit=${limit}&offset=${offset}&order=volume24hr&ascending=false`;
  if (tagId !== null) {
    url += `&tag_id=${tagId}&related_tags=true`;
  }

  const proxyUrl = `/api/proxy?url=${encodeURIComponent(url)}`;
  const res = await fetch(proxyUrl);
  if (!res.ok) throw new Error(`API error: ${res.status}`);
  const data = await res.json();
  return data as PolymarketEvent[];
}

export function parseOutcomes(market: {
  outcomes: string;
  outcomePrices: string;
}): { label: string; price: number }[] {
  try {
    const labels: string[] = JSON.parse(market.outcomes);
    const prices: string[] = JSON.parse(market.outcomePrices);
    return labels.map((label, i) => ({
      label,
      price: parseFloat(prices[i]) || 0,
    }));
  } catch {
    return [];
  }
}

export function formatVolume(vol: number): string {
  if (vol >= 1_000_000) return `$${(vol / 1_000_000).toFixed(1)}M`;
  if (vol >= 1_000) return `$${(vol / 1_000).toFixed(1)}K`;
  return `$${vol.toFixed(0)}`;
}

export function formatLiquidity(liq: string | number): string {
  const n = typeof liq === "string" ? parseFloat(liq) : liq;
  if (isNaN(n)) return "$0";
  if (n >= 1_000_000) return `$${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000) return `$${(n / 1_000).toFixed(1)}K`;
  return `$${n.toFixed(0)}`;
}

