import React from "react";
import { PolymarketEvent } from "../types";
import { parseOutcomes, formatVolume, formatLiquidity } from "../lib/api";
import { Badge } from "@/components/ui/badge";
import { TrendingUp, BarChart3, Droplets } from "lucide-react";
import { motion } from "framer-motion";

function PriceBar({
  label,
  price,
  color,
}: {
  label: string;
  price: number;
  color: string;
}) {
  const pct = Math.round(price * 100);
  return (
    <div className="flex items-center gap-2 text-xs">
      <span className="w-16 truncate text-zinc-400 shrink-0">{label}</span>
      <div className="flex-1 h-5 bg-zinc-800 relative overflow-hidden">
        <motion.div
          className="h-full absolute left-0 top-0"
          style={{ backgroundColor: color }}
          initial={{ width: 0 }}
          animate={{ width: `${pct}%` }}
          transition={{ duration: 0.6, ease: "easeOut" }}
        />
        <span className="absolute inset-0 flex items-center justify-center text-white font-bold text-[11px] z-10">
          {pct}¢
        </span>
      </div>
    </div>
  );
}

const OUTCOME_COLORS = [
  "#60a5fa",
  "#f87171",
  "#34d399",
  "#fbbf24",
  "#a78bfa",
  "#fb923c",
  "#38bdf8",
  "#e879f9",
];

interface MarketCardProps {
  event: PolymarketEvent;
}

export default function MarketCard({ event }: MarketCardProps) {
  const mainMarket = event.markets?.[0];
  if (!mainMarket) return null;

  const outcomes = parseOutcomes(mainMarket);
  const topOutcome = outcomes.length > 0 ? outcomes[0] : null;
  const isBinary = outcomes.length === 2;
  const displayOutcomes = isBinary ? outcomes.slice(0, 1) : outcomes.slice(0, 6);
  const hasMore = event.markets.length > 1;

  return (
    <motion.div
      className="bg-zinc-900 border border-zinc-800 p-3 hover:border-zinc-600 transition-colors cursor-pointer group"
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
    >
      <div className="flex gap-3">
        {event.image && (
          <img
            src={event.image}
            alt=""
            className="w-10 h-10 object-cover shrink-0 mt-0.5"
            onError={(e) => {
              (e.target as HTMLImageElement).style.display = "none";
            }}
          />
        )}
        <div className="flex-1 min-w-0">
          <h3 className="text-sm font-semibold text-zinc-100 leading-tight line-clamp-2 group-hover:text-white">
            {event.title}
          </h3>

          <div className="flex items-center gap-3 mt-1.5 text-[11px] text-zinc-500">
            <span className="flex items-center gap-1">
              <BarChart3 className="w-3 h-3" />
              Vol {formatVolume(event.volume)}
            </span>
            <span className="flex items-center gap-1">
              <TrendingUp className="w-3 h-3" />
              24h {formatVolume(event.volume24hr)}
            </span>
            <span className="flex items-center gap-1">
              <Droplets className="w-3 h-3" />
              {formatLiquidity(event.liquidity)}
            </span>
          </div>
        </div>

        {topOutcome && isBinary && (
          <div className="shrink-0 text-right">
            <div
              className="text-lg font-bold"
              style={{ color: topOutcome.price >= 0.5 ? "#34d399" : "#f87171" }}
            >
              {Math.round(topOutcome.price * 100)}%
            </div>
            <div className="text-[10px] text-zinc-500 uppercase">
              {topOutcome.label}
            </div>
          </div>
        )}
      </div>

      <div className="mt-2.5 space-y-1">
        {isBinary ? (
          <PriceBar
            label={outcomes[0].label}
            price={outcomes[0].price}
            color={OUTCOME_COLORS[0]}
          />
        ) : (
          displayOutcomes.map((o, i) => (
            <PriceBar
              key={o.label}
              label={o.label}
              price={o.price}
              color={OUTCOME_COLORS[i % OUTCOME_COLORS.length]}
            />
          ))
        )}
      </div>

      {hasMore && (
        <div className="mt-2 flex items-center gap-1.5 flex-wrap">
          {event.markets.slice(1, 4).map((m) => {
            const mOutcomes = parseOutcomes(m);
            const top = mOutcomes[0];
            return (
              <Badge
                key={m.id}
                variant="secondary"
                className="text-[10px] bg-zinc-800 text-zinc-400 border-zinc-700 px-1.5 py-0 font-normal max-w-[180px] truncate"
              >
                {m.question?.slice(0, 40)}
                {top ? ` · ${Math.round(top.price * 100)}¢` : ""}
              </Badge>
            );
          })}
          {event.markets.length > 4 && (
            <Badge
              variant="outline"
              className="text-[10px] text-zinc-500 border-zinc-700 px-1.5 py-0"
            >
              +{event.markets.length - 4} more
            </Badge>
          )}
        </div>
      )}

      {event.tags && event.tags.length > 0 && (
        <div className="mt-2 flex gap-1 flex-wrap">
          {event.tags.slice(0, 3).map((tag) => (
            <span
              key={tag.id}
              className="text-[10px] px-1.5 py-0.5 bg-zinc-800/50 text-zinc-500 border border-zinc-800"
            >
              {tag.label}
            </span>
          ))}
        </div>
      )}
    </motion.div>
  );
}

